import{mostrarResultado}from"../../renderResult.js";export function render(t){const{accion:o,articulos:n,mensaje:c,exito:d,stockActual:a}=t.respuesta;if("listar"!==o&&o){mostrarResultado(`\n            <p style="color:${!1===d?"#e74c3c":"#2ecc71"}">${c}</p>\n            ${void 0!==a?`<p>Stock actual: <b>${a}</b></p>`:""}\n            <button onclick="sendPrompt('accion=listar')">← Volver al listado</button>\n        `)}else{const t=n.map(t=>`\n            <tr>\n                <td>${t.codigo}</td><td>${t.descripcion}</td>\n                <td>${t.precioCompra} €</td><td>${t.precioVenta} €</td>\n                <td>${t.stock}</td>\n                <td>\n                    <button onclick="sendPrompt('accion=modificar&codigo=${t.codigo}')">✏️</button>\n                    <button onclick="sendPrompt('accion=baja&codigo=${t.codigo}')">🗑</button>\n                    <button onclick="sendPrompt('accion=entrada&codigo=${t.codigo}')">📥</button>\n                    <button onclick="sendPrompt('accion=salida&codigo=${t.codigo}')">📤</button>\n                </td>\n            </tr>`).join("");mostrarResultado(`\n            <button onclick="sendPrompt('accion=alta')">+ Nuevo artículo</button>\n            <h3>GESTISIMAL - Almacén</h3>\n            <table border="1">\n                <thead><tr><th>Código</th><th>Descripción</th><th>P.Compra</th><th>P.Venta</th><th>Stock</th><th>Acciones</th></tr></thead>\n                <tbody>${t}</tbody>\n            </table>\n        `)}}//# sourceMappingURL=ejercicio4.js.map
